class App{intit(){this.cacheDom(),this.initEvents()}cacheDom(){this.btn=document.querySelector("button.md-secondary"),this.body=document.querySelector("body"),this.profile=document.querySelector(".profile-card"),this.dd=document.querySelector(".drop-down"),this.modal=document.querySelector(".modal")}initEvents(){this.btn.addEventListener("click",(()=>{this.toggleClass()}))}toggleClass(){this.profile.classList.contains("show")?this.profile.classList.contains("show")&&(this.profile.classList.remove("show"),this.profile.classList.add("hidden")):(this.profile.classList.add("show"),this.profile.classList.remove("hidden"))}toggleModal(){}}let app=new App;app.intit();